// Packages the incoming email into a format that the easybits Extractor can read.
// You don't need to understand or modify this — just paste it as-is.

const email = $input.item.json;

// Pull the fields out of the Gmail node, with safe fallbacks
const subject = email.subject || '(no subject)';
const from = email.from?.value?.[0]?.address || email.from?.text || 'unknown sender';
const date = email.date || '';
const body = email.text || email.snippet || '(empty body)';

// Build the document content
const content = `Subject: ${subject}
From: ${from}
Date: ${date}

${body}`;

// Escape characters that have special meaning in PDFs
const escape = (s) => s.replace(/\\/g, '\\\\').replace(/\(/g, '\\(').replace(/\)/g, '\\)');

// Wrap long lines so they fit on the page
const lines = content.split('\n').flatMap((line) => {
  if (line.length === 0) return [''];
  const wrapped = [];
  for (let i = 0; i < line.length; i += 90) {
    wrapped.push(line.slice(i, i + 90));
  }
  return wrapped;
});

// Build the text stream that the PDF will render
let stream = 'BT\n/F1 10 Tf\n50 780 Td\n12 TL\n';
for (const line of lines) {
  stream += `(${escape(line)}) Tj\nT*\n`;
}
stream += 'ET';

const streamLength = Buffer.byteLength(stream, 'utf-8');

// Assemble the PDF structure
const objects = [
  '1 0 obj << /Type /Catalog /Pages 2 0 R >> endobj',
  '2 0 obj << /Type /Pages /Kids [3 0 R] /Count 1 >> endobj',
  '3 0 obj << /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >> endobj',
  `4 0 obj << /Length ${streamLength} >> stream\n${stream}\nendstream endobj`,
  '5 0 obj << /Type /Font /Subtype /Type1 /BaseFont /Helvetica >> endobj',
];

// Calculate byte offsets for the cross-reference table
const header = '%PDF-1.4\n';
const offsets = [0];
let cursor = Buffer.byteLength(header, 'utf-8');
for (const obj of objects) {
  offsets.push(cursor);
  cursor += Buffer.byteLength(obj + '\n', 'utf-8');
}

// Build the xref table
let xref = `xref\n0 ${objects.length + 1}\n+1234567890 f \n`;
for (let i = 1; i <= objects.length; i++) {
  xref += `${offsets[i].toString().padStart(10, '0')} 00000 n \n`;
}

const trailer = `trailer << /Size ${objects.length + 1} /Root 1 0 R >>\nstartxref\n${cursor}\n%%EOF`;

const pdf = header + objects.join('\n') + '\n' + xref + trailer;

// Hand the document off to the next node as a binary file
return {
  json: { subject, from, date },
  binary: {
    data: {
      data: Buffer.from(pdf, 'binary').toString('base64'),
      mimeType: 'application/pdf',
      fileName: 'email.pdf',
    },
  },
};
